VALUES
  ('real-estate-moex-01134', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲當面向乙表示願以一千萬元出售甲所有之A房屋予乙，乙當場未置可否，經三日後乙回覆甲願以一千 萬元購買A屋。就甲、乙各自之意思表示，下列敘述何者最正確？', '["甲之意思表示為要約，乙之意思表示為承諾", "甲之意思表示為要約引誘，乙之意思表示為要約", "甲之意思表示為要約，乙之意思表示為要約引誘", "甲之意思表示為要約，乙之意思表示為新要約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01135', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關加害人應負損害賠償責任之敘述，何者最正確？', '["受僱人甲因執行職務不法侵害第三人乙之權利時，原則上僅由甲對乙負損害賠償責任", "限制行為能力人甲不法侵害第三人乙之權利時，即使甲於行為時有識別能力，原則上由甲及其法定代理 人對乙連帶負損害賠償責任", "法人甲之董事丙因執行職務對第三人乙造成損害時，因甲無實體存在，故僅由丙單獨對乙負損害賠償責任", "甲、丙、丁三人共謀聯手圍毆乙，實際下手時，如丁僅在一旁叫囂助陣，則丁不須對乙因被毆所生損害 負賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01136', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙、丙三人締結合夥契約，並以每月三萬元租金租用甲所有之房屋為共同經營事業之場所。惟因合夥 事業經營不順致合夥解散，解散後已無合夥財產清償累計三個月未支付之租金。就積欠之九萬元租金， 出租人甲得向乙、丙為如何之主張？', '["甲僅得分別向乙、丙請求各應支付三萬元", "甲僅得分別向乙、丙請求各應支付四萬五千元", "甲僅得向乙或丙請求應支付六萬元", "甲僅得向乙或丙請求應支付九萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01137', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與乙締結將甲所有A屋出售予乙之買賣契約後，A屋於甲依約交付予乙前因火災燒毀致不能給付。下 列敘述何者最正確？', '["如A屋之燒毀係可歸責於甲之事由所致，乙僅須支付二分之一之價金", "如A屋之燒毀係可歸責於乙之事由所致，甲僅得請求支付二分之一之價金", "如A屋之燒毀係可歸責於甲之事由所致，乙得解除契約", "如A屋之燒毀係可歸責於第三人丙之事由所致，乙仍須支付二分之一之價金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01138', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與乙約定，甲不得將其對乙之非不得讓與的A金錢債權讓與予第三人。事後，甲卻違反與乙之約定， 將A債權讓與予丙。就此情形，下列敘述何者最正確？', '["甲、乙之約定違反誠信原則，無效。甲、丙間之讓與契約有效", "甲、乙之約定有效。但如丙為善意第三人，甲、乙之約定不得對抗丙", "無論債權人如何變動，債務人乙皆須清償，故甲、乙間之約定無效", "甲、乙之約定效力未定。甲、丙之讓與契約無效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01139', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '被繼承人甲於生前立下遺囑。下列敘述何者最正確？', '["甲遺囑中之受遺贈人於遺囑生效前死亡者，其遺贈無效", "甲得以遺囑禁止遺產之分割，但其禁止之效力以五年為限", "未滿十六歲之甲於經其法定代理人允許時，得立遺囑", "甲遺囑中之受遺贈人拋棄遺贈者，自為拋棄之意思表示時發生效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01140', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲借款十萬元予乙，約定於半年後清償。下列敘述何者最正確？', '["對於乙之期前清償，甲不得為反對之意思表示", "甲請求乙為期前清償時，乙不得拒絕", "乙之期前清償縱經甲受領，乙仍得以其期限利益受損，向甲主張不當得利返還請求權", "乙之期前清償如經甲受領，則乙不得再向甲主張不當得利返還請求權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01141', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲對乙有於今年（下同）5月31日到期之買賣價金金錢債權，乙對甲有於6月30日到期之消費借貸金錢 債權。甲於7月1日主張抵銷，乙於7月5日回覆同意甲之抵銷的主張。試問：因甲主張抵銷而消滅之 債之關係，於何時發生效力？', '["5月31日", "6月30日", "7月1日", "7月5日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01142', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙間約定由甲幫乙為訂約之媒介，並由乙給付報酬予甲。甲、乙所定契約之名稱為下列何者？', '["承攬契約", "代辦契約", "僱傭契約", "居間契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01143', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '出賣人甲依其與買受人乙間之動產買賣契約，於約定之日合法提出給付，卻遭乙拒絕受領。依實務見解， 就乙拒絕受領之法律效果，下列敘述何者最正確？', '["甲得解除契約", "甲不得向乙請求繼續保管給付物之必要費用", "甲得拋棄對該動產之占有", "甲對標的物之保管，僅就故意負其責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
